#include <bits/stdc++.h>
using namespace std;

const int N=3100;

int c,T,n,k,a[N],ans[N],len,f[N],lst[N];
long long g[N];
char s[N];

bool check(int x){
    if(x<n) return false;
    bool flag=true;
    for(int i=1;i+n-1<=x;i++){
        bool eq=true;
        for(int j=1;j<=n && eq;j++)
            if(a[i+j-1]!=s[j]-'0')
                eq=false;
        if(eq){
            flag=false;
            break;
        }
    }
    if(flag) return false;
    int cnt=0;
    for(int l=1;l<=x;l++)
        for(int r=l;r<=x;r++){
            if(a[r]!=s[r-l+1]-'0'){
                if(a[r]<s[r-l+1]-'0')
                    cnt+=x-r+1;
                break;
            }else if(r-l+1<n)
                cnt++;
            else
                break;
        }
    return cnt==k;
}

void dfs(int x){
    if(x-1>=len) return;
    if(check(x-1)){
        len=x-1;
        for(int i=1;i<x;i++)
            ans[i]=a[i];
    }
    a[x]=0;
    dfs(x+1);
    a[x]=1;
    dfs(x+1);
}

int main(){
    scanf("%d%d",&c,&T);
    while(T--){
        scanf("%d%d",&n,&k);
        scanf("%s",s+1);
        if(c<=3){
            len=16;
            dfs(1);
            if(len==16) puts("Impossible");
            else{
                for(int i=1;i<=len;i++)
                    printf("%d",ans[i]);
                puts("");
            }
        }else if(c<=6){
            for(int i=1;i<=k;i++)
                if(i<n) g[i]=1ll*i*(i+1)/2;
                else g[i]=1ll*(n-1)*(2*i-n+2)/2;
            if(g[n]>k || n==1){
                puts("Impossible");
                continue;
            }
            memset(f,0x3f,sizeof(f));
            f[0]=-1;
            for(int i=g[n];i<=k;i++)
                for(int j=1;g[j]<=i;j++)
                    if(f[i]>f[i-g[j]]+j+1)
                        f[i]=f[i-g[j]]+j+1,lst[i]=j;
            for(int i=k;i;i-=g[lst[i]]){
                for(int j=1;j<=lst[i];j++)
                    printf("0");
                if(g[lst[i]]<i)
                    printf("1");
            }
            puts("");
        }else
            puts("Impossible");
    }
    return 0;
}
